css:
:host { display: block; }
.stats { padding: 4rem 2rem; text-align: center; }
h2 { font-size: 2rem; color: white; margin: 0 0 3rem; }
.grid { display: flex; justify-content: center; gap: 4rem; flex-wrap: wrap; }
.stat { min-width: 120px; }
.value { font-size: 3.5rem; font-weight: 800; color: var(--primary); display: block; line-height: 1; }
.prefix, .suffix { font-size: 2rem; font-weight: 700; color: var(--primary); }
.label { display: block; margin-top: 0.5rem; font-size: 0.875rem; color: #adadb0; text-transform: uppercase; letter-spacing: 0.08em; }

js:
gsap.registerPlugin(ScrollTrigger);
root.querySelectorAll('.value').forEach(el => {
  const target = parseInt(el.dataset.target, 10);
  gsap.fromTo(el,
    { textContent: 0 },
    {
      textContent: target,
      duration: 2,
      ease: 'power2.out',
      snap: { textContent: 1 },
      scrollTrigger: {
        trigger: el,
        start: 'top 85%',
        once: true
      }
    }
  );
});
